from pathlib import Path

root = Path(r"C:\Users\Gebruiker\Rezzerv_Github")

pre = root / "backend/app/receipt_ingestion/preprocessing/receipt_image_preprocessing.py"
req = root / "backend/requirements.txt"

pre.write_text('from __future__ import annotations\n\nfrom dataclasses import asdict, dataclass\nfrom pathlib import Path\nfrom typing import Any\n\ntry:\n    import cv2\n    import numpy as np\nexcept Exception:\n    cv2 = None\n    np = None\n\n\nIMAGE_SUFFIXES = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}\nLANDSCAPE_ASPECT_LIMIT = 1.20\n\n\n@dataclass\nclass ReceiptImagePreprocessingDecision:\n    preprocessing_step: str\n    selected_route: str\n    applied_steps: list[str]\n    fallback_reason: list[str]\n    perspective_normalization: dict[str, Any] | None\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _decode_image(file_bytes: bytes):\n    if cv2 is None or np is None:\n        return None\n    data = np.frombuffer(file_bytes, dtype=np.uint8)\n    return cv2.imdecode(data, cv2.IMREAD_COLOR)\n\n\ndef _encode_image_png(image) -> bytes | None:\n    if cv2 is None:\n        return None\n    ok, encoded = cv2.imencode(".png", image)\n    return bytes(encoded.tobytes()) if ok else None\n\n\ndef _rotate_landscape_to_portrait(image):\n    height, width = image.shape[:2]\n    if height > 0 and (width / height) >= LANDSCAPE_ASPECT_LIMIT:\n        return cv2.rotate(image, cv2.ROTATE_90_COUNTERCLOCKWISE), True\n    return image, False\n\n\ndef apply_receipt_image_preprocessing(file_bytes: bytes, filename: str) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    """Safe runtime preprocessing for receipt ingestion.\n\n    R9-22A:\n    Experimental AI/background-removal and forced perspective extraction are\n    disabled for runtime stability. Bad receipt photos must be handled by the\n    receipt image quality gate, not by unsafe automatic reconstruction.\n\n    This function intentionally does not determine functional receipt status.\n    """\n    suffix = Path(filename or "").suffix.lower()\n    if suffix and suffix not in IMAGE_SUFFIXES:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["unsupported_image_suffix"],\n            None,\n        )\n\n    image = _decode_image(file_bytes)\n    if image is None:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["image_decode_failed_or_cv2_unavailable"],\n            None,\n        )\n\n    applied_steps: list[str] = []\n\n    image, rotated = _rotate_landscape_to_portrait(image)\n    if rotated:\n        applied_steps.append("rotate_landscape_to_portrait")\n\n    output = _encode_image_png(image)\n    if not output:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            applied_steps,\n            ["output_encode_failed"],\n            None,\n        )\n\n    route = "original" if not applied_steps else "+".join(applied_steps)\n    return output, ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        route,\n        applied_steps,\n        [],\n        None,\n    )\n', encoding="utf-8")

requirements = req.read_text(encoding="utf-8")
requirements = requirements.replace("rembg[cpu]>=2.0,<3\n", "")
requirements = requirements.replace("rembg>=2.0,<3\n", "")
req.write_text(requirements, encoding="utf-8")

print("R9-22A toegepast: experimentele rembg/background-removal uit runtime gehaald.")
